const express = require('express');
const session = require('express-session');
const bodyParser = require('body-parser');
const twilio = require('twilio');
const crypto = require('crypto');

const app = express();
const port = 3000;

app.use(bodyParser.json());
app.use(session({
    secret: crypto.randomBytes(32).toString('hex'), // More secure secret
    resave: false,
    saveUninitialized: true,
    cookie: { secure: true } // Ensure this is true in production with HTTPS
}));

const accountSid = 'your_twilio_account_sid';
const authToken = 'your_twilio_auth_token';
const twilioClient = twilio(accountSid, authToken);

const users = {}; // In-memory user storage for demo purposes

app.post('/send-code', (req, res) => {
    const { phoneNumber } = req.body;
    const code = crypto.randomInt(100000, 999999).toString();
    req.session.code = code;
    req.session.phoneNumber = phoneNumber;
    req.session.codeAttempts = 0; // Track attempts
    req.session.codeExpiry = Date.now() + 300000; // Code valid for 5 minutes

    twilioClient.messages.create({
        body: `Your verification code is ${code}`,
        from: 'your_twilio_phone_number',
        to: phoneNumber
    })
    .then(() => res.status(200).send('Code sent'))
    .catch(err => res.status(500).send('Error sending code'));
});

app.post('/verify-code', (req, res) => {
    const { code } = req.body;
    const now = Date.now();

    if (req.session.codeExpiry < now) {
        return res.status(400).send('Code expired');
    }

    if (req.session.codeAttempts >= 3) {
        return res.status(400).send('Too many attempts');
    }

    if (req.session.code && req.session.code === code) {
        res.status(200).send('Code verified');
        delete req.session.code;
    } else {
        req.session.codeAttempts += 1; // Increment attempts
        res.status(400).send('Invalid code');
    }
});

app.listen(port, () => {
    console.log(`Server running at http://localhost:${port}`);
});